238	  label: string;
239	  value: string;
240	  onChange: (next: string) => void;
241	  onBlur?: () => void;
242	  autoCapitalize?: TextInputProps['autoCapitalize'];
243	  autoCorrect?: boolean;
244	  autoComplete?: TextInputProps['autoComplete'];
245	  keyboardType?: TextInputProps['keyboardType'];
