252	  label,
253	  value,
254	  onChange,
255	  onBlur,
256	  autoCapitalize,
257	  autoCorrect,
258	  autoComplete,
259	  keyboardType,
260	  placeholder,
261	  error,
262	  testID,
263	}: FieldProps) {
264	  const hasError = !!error;
265	  return (
266	    <View style={styles.field}>
267	      <Text style={[textStyles.caption, styles.label]}>{label}</Text>
268	      <View style={[styles.inputWrap, shadows.hard, hasError && styles.inputWrapError]}>
269	        <TextInput
270	          value={value}
271	          onChangeText={onChange}
272	          onBlur={onBlur}
273	          autoCapitalize={autoCapitalize}
274	          autoCorrect={autoCorrect}
275	          autoComplete={autoComplete}
276	          keyboardType={keyboardType}
277	          placeholder={placeholder}
278	          placeholderTextColor={colors.ink40}
279	          style={[textStyles.body, styles.input]}
280	          accessibilityLabel={label}
281	          testID={testID}
282	        />
283	      </View>
284	      {/* Always mounted so `accessibilityLiveRegion` can announce content
285	          changes on Android — a node that mounts alongside its first content
286	          does not reliably fire an announcement there. */}
287	      <Text
288	        style={[textStyles.caption, styles.errorText, !hasError && styles.errorHidden]}
289	        accessibilityLiveRegion="polite"
290	        importantForAccessibility={hasError ? 'yes' : 'no-hide-descendants'}
291	      >
292	        {error ?? ''}
293	      </Text>
294	    </View>
295	  );
296	}
